class Solution:
    def minOperations(self, nums):
        arr = list(nums)
        ops = 0
        while any(v > 0 for v in arr):
            odd_count = 0
            for i in range(len(arr)):
                if arr[i] % 2 == 1:
                    arr[i] -= 1
                    odd_count += 1
            ops += odd_count
            if any(v > 0 for v in arr):
                for i in range(len(arr)):
                    arr[i] //= 2
                ops += 1
        return ops

