class Solution:
    def minOperations(self, nums):
        total = 0
        max_shift = 0
        for x in nums:
            total += bin(x).count('1')
            shift = x.bit_length() - 1 if x > 0 else 0
            if shift > max_shift:
                max_shift = shift
        return total + max_shift

