var minOperations = function(nums) {
    let total = 0;
    let maxShift = 0;
    for (const x of nums) {
        let bits = 0;
        let v = x;
        while (v > 0) {
            bits += v & 1;
            v = Math.floor(v / 2);
        }
        total += bits;
        let shift = 0;
        let t = x;
        while (t > 1) {
            t = Math.floor(t / 2);
            shift++;
        }
        if (shift > maxShift) maxShift = shift;
    }
    return total + maxShift;
};
